#include <iostream>
#include <vector>
#include <climits>
using namespace std;

int main() {
    int n;

    // Input the number of elements
    cin >> n;

    vector<int> arr(n);

    // Input the elements of the array
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }

    // Initialize largest and smallest
    int largest = arr[0];
    int smallest = arr[0];

    // Iterate through the array to find largest and smallest
    for (int i = 1; i < n; i++) {
        if (arr[i] > largest) {
            largest = arr[i];
        }
        if (arr[i] < smallest) {
            smallest = arr[i];
        }
    }

    // Output the results
    cout << "Largest: " << largest << endl;
    cout << "Smallest: " << smallest << endl;

    return 0;
}

